// Ordered from broadest to narrowest.
// "allowed_levels" = which dashboard levels this access type can view.
// super_admin is handled separately — gets everything.

export const LEVEL_ACCESS_CONFIG = {
  region: ["region", "area", "cgs", "station"],
  area:   ["area", "cgs", "station"],
  station: ["station"],
};

// For each dashboard level, what child table does it show?
// This tells the frontend what to render in the table below the stats.
export const CHILD_LEVEL = {
  country: "region",
  region:  "area",
  area:    "cgs",
  cgs:     "station",
  station: null, // leaf node — no child table, show compressor/dispenser/device
};

export function canAccessLevel(userLevel, userRole, requestedLevel) {
  if (userRole === "super_admin") return true;
  const allowed = LEVEL_ACCESS_CONFIG[userLevel] ?? [];
  return allowed.includes(requestedLevel);
}

