import { prisma } from "../lib/prisma.js";
import { logError, logEvent, logTransaction } from "../services/logs.service.js";
import { isUnrestricted } from "../helpers/filterHelpers.js";

// GET /api/dashboard
// Returns the default landing data based on the user's level.
// Frontend uses this to decide which dashboard page to render first.
export const getDefaultDashboard = async (req, res) => {
  try {
    await logEvent(req);

    const { role, level, regions, areas, stations } = req.user;
    const filter = req.accessFilter;
    const unrestricted = isUnrestricted(filter);

    let defaultLevel;
    let data;

    if (role === "super_admin") {
      // super_admin lands on country view — list of all regions
      defaultLevel = "country";
      data = await prisma.region.findMany({ orderBy: { name: "asc" } });

    } else if (level === "region") {
      defaultLevel = "region";
      data = await prisma.region.findMany({
        where: { name: { in: regions } },
        orderBy: { name: "asc" },
      });

    } else if (level === "area") {
      defaultLevel = "area";
      data = await prisma.area.findMany({
        where: { name: { in: areas } },
        orderBy: { name: "asc" },
      });

    } else if (level === "station") {
      defaultLevel = "station";
      data = await prisma.station.findMany({
        where: { name: { in: stations } },
        orderBy: { name: "asc" },
      });
    }

    await logTransaction(req);
    res.status(200).json({ success: true, default_level: defaultLevel, data });
  } catch (err) {
    await logError(req, err);
    res.status(500).json({ success: false, error: err.message });
  }
};

// GET /api/dashboard/region/:regionName
export const getRegionDashboard = async (req, res) => {
  try {
    await logEvent(req);

    const { regionName } = req.params;
    const filter = req.accessFilter;
    const unrestricted = isUnrestricted(filter);

    // Access check — is this region within the user's allowed scope?
    if (!unrestricted && !filter.region?.in.includes(regionName)) {
      return res.status(403).json({ success: false, error: "Access denied" });
    }

    const [region, areas] = await Promise.all([
      prisma.region.findFirst({ where: { name: regionName } }),
      prisma.area.findMany({
        where: {
          region: regionName,
          // if user has specific area restrictions, apply them
          ...(filter.area && { name: { in: filter.area.in } }),
        },
        orderBy: { name: "asc" },
      }),
    ]);

    if (!region) {
      return res.status(404).json({ success: false, error: "Region not found" });
    }

    await logTransaction(req);
    res.status(200).json({
      success: true,
      dashboard_level: "region",
      entity: region,
      // areas is what the frontend renders as the clickable table
      // clicking a row → navigate to /dashboard/area/:areaName
      children: { level: "area", data: areas },
    });
  } catch (err) {
    await logError(req, err);
    res.status(500).json({ success: false, error: err.message });
  }
};

// GET /api/dashboard/area/:areaName
export const getAreaDashboard = async (req, res) => {
  try {
    await logEvent(req);

    const { areaName } = req.params;
    const filter = req.accessFilter;
    const unrestricted = isUnrestricted(filter);

    if (!unrestricted && filter.area && !filter.area.in.includes(areaName)) {
      return res.status(403).json({ success: false, error: "Access denied" });
    }

    const [area, stations] = await Promise.all([
      prisma.area.findFirst({ where: { name: areaName } }),
      prisma.station.findMany({
        where: {
          area: areaName,
          ...(filter.station && { name: { in: filter.station.in } }),
        },
        orderBy: { name: "asc" },
      }),
    ]);

    if (!area) {
      return res.status(404).json({ success: false, error: "Area not found" });
    }

    await logTransaction(req);
    res.status(200).json({
      success: true,
      dashboard_level: "area",
      entity: area,
      // clicking a row → navigate to /dashboard/station/:stationName
      children: { level: "station", data: stations },
    });
  } catch (err) {
    await logError(req, err);
    res.status(500).json({ success: false, error: err.message });
  }
};

