// GET /api/dashboard/station/:stationName
export const getStationDashboard = async (req, res) => {
  try {
    await logEvent(req);

    const { stationName } = req.params;
    const filter = req.accessFilter;
    const unrestricted = isUnrestricted(filter);

    if (!unrestricted && filter.station && !filter.station.in.includes(stationName)) {
      return res.status(403).json({ success: false, error: "Access denied" });
    }

    const [station, compressors, dispensers, devices] = await Promise.all([
      prisma.station.findFirst({ where: { name: stationName } }),
      prisma.compressor.findMany({ where: { station: stationName }, orderBy: { name: "asc" } }),
      prisma.dispenser.findMany({ where: { station: stationName }, orderBy: { name: "asc" } }),
      prisma.device.findMany({ where: { station: stationName } }),
    ]);

    if (!station) {
      return res.status(404).json({ success: false, error: "Station not found" });
    }

    await logTransaction(req);
    res.status(200).json({
      success: true,
      dashboard_level: "station",
      entity: station,
      // each asset type is a separate clickable table
      // clicking compressor row → /dashboard/compressor/:id
      // clicking dispenser row → /dashboard/dispenser/:id
      children: {
        compressors,
        dispensers,
        devices,
      },
    });
  } catch (err) {
    await logError(req, err);
    res.status(500).json({ success: false, error: err.message });
  }
};

// GET /api/dashboard/compressor/:compressorId
export const getCompressorDashboard = async (req, res) => {
  try {
    await logEvent(req);

    const id = parseInt(req.params.compressorId);

    const compressor = await prisma.compressor.findUnique({ where: { id } });

    if (!compressor) {
      return res.status(404).json({ success: false, error: "Compressor not found" });
    }

    // Access check — verify this compressor belongs to a station the user can access
    const filter = req.accessFilter;
    const unrestricted = isUnrestricted(filter);
    if (!unrestricted && filter.station && !filter.station.in.includes(compressor.station)) {
      return res.status(403).json({ success: false, error: "Access denied" });
    }

    await logTransaction(req);
    res.status(200).json({
      success: true,
      dashboard_level: "compressor",
      entity: compressor,
    });
  } catch (err) {
    await logError(req, err);
    res.status(500).json({ success: false, error: err.message });
  }
};

// GET /api/dashboard/dispenser/:dispenserId
export const getDispenserDashboard = async (req, res) => {
  try {
    await logEvent(req);

    const id = parseInt(req.params.dispenserId);

    const dispenser = await prisma.dispenser.findUnique({ where: { id } });

    if (!dispenser) {
      return res.status(404).json({ success: false, error: "Dispenser not found" });
    }

    const filter = req.accessFilter;
    const unrestricted = isUnrestricted(filter);
    if (!unrestricted && filter.station && !filter.station.in.includes(dispenser.station)) {
      return res.status(403).json({ success: false, error: "Access denied" });
    }

    await logTransaction(req);
    res.status(200).json({
      success: true,
      dashboard_level: "dispenser",
      entity: dispenser,
