import bcrypt from "bcrypt";

import { prisma } from "../lib/prisma.js";
import { logError, logEvent, logTransaction } from "../services/logs.service.js";

export const getRoles = async (req, res) => {
  try {
    await logEvent(req);

    const callerRole = req.user.role;

    const excludedRoles = ["super_admin"];

    if (callerRole === "admin") {
      excludedRoles.push("admin"); 
    }

    const roles = await prisma.role.findMany({
      where: {
        name: { notIn: excludedRoles },
      },
      select: { id: true, name: true },
    });

    await logTransaction(req);

    res.status(200).json({ success: true, data: roles });
  } catch (err) {
    await logError(req, err);
    res.status(500).json({ success: false, error: err.message });
  }
};

export const createUser = async (req, res) => {
  try {
    await logEvent(req);

    const { first_name, last_name, email, password, phone, role_id, level, regions, areas, stations } = req.body;

    if (!first_name || !last_name || !email || !password || !role_id || !level) {
      return res.status(400).json({ success: false, error: "Missing required fields" });
    }

    const hashedPassword = await bcrypt.hash(password, 10);

    const user = await prisma.user.create({
      data: {
        first_name,
        last_name,
        email,
        password: hashedPassword,
        phone,
        role_id,
        access: {
          create: {
            level,
            regions:  regions  || [],
            areas:    areas    || [],
            stations: stations || [],
          },
        },
      },
      include: { role: true, access: true },
    });

    await logTransaction(req);

    res.status(201).json({
      success: true,
      data: {
        id:     user.id,
        full_name: `${user.first_name} ${user.last_name}`,
        email:  user.email,
        phone:  user.phone,
        role:   user.role.name,
        access: user.access,
      },
    });
  } catch (err) {
    await logError(req, err);
    res.status(500).json({ success: false, error: err.message });
  }
};

export const getUsers = async (req, res) => {
  try {
    await logEvent(req);

    const users = await prisma.user.findMany({
      select: {
        id:         true,
        first_name: true,
        last_name:  true,
        email:      true,
        phone:      true,
        is_active:  true,
        created_at: true,
        role:       { select: { name: true } },
